var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"언제나 한 발 늦는구나, 불경하기 짝이 없는 방랑자여.","JPN":"いつも一足遅れて来るのだな、不敬極まる放浪者よ。","ENG":"You're always a step behind, ye filthy Wayfarer.","TWN":"總是晚一步啊，狂妄的流浪者。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너를 위해 불러들였던 짐승들은 어떠했느냐.","JPN":"貴様のためにおびき寄せた獣は気に入ってくれたか。","ENG":"How did you like the beasts I summoned for you?","TWN":"為你喚來的那些野獸如何啊。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......그녀를 우롱했군.","JPN":"……彼女を愚弄したな。","ENG":"You've made a mockery of her...","TWN":"……你竟愚弄了她。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"처음부터 그 아이는 인질이었나.","JPN":"最初からあの子は人質だったのか。","ENG":"So the child was nothing but a hostage all along.","TWN":"從一開始那個孩子就是人質吧。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"미물들 사이에 숨어 살면서, 그들에 대해선 여전히 모르는구나.","JPN":"下等な微物に紛れて生きているにもかかわらず、彼らについて相変わらず無知なのだな。","ENG":"You dwell among the mortals, yet you haven't learned a thing about them.","TWN":"你隱匿在這些微不足道的廢物身邊生活，卻對他們還不是很瞭解啊。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"미물들은...... 자신이 소중하다고 여기는 상대의 안위에 충동적으로 반응하지.","JPN":"下等な微物は……自分が大切だと思っている相手の安否に衝動的に反応する。","ENG":"These mortals... always respond on impulse when it comes to the well-being of those they hold dear.","TWN":"微不足道的廢物……會因為自己珍視的對方安危與否而做出衝動的反應。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그것을 활용하면, 아주 작은 자극만으로도 헛된 반항심을 무너뜨릴 수 있다.","JPN":"それを活用すれば、ほんの少しの刺激で無駄な反抗を抑えることができる。","ENG":"If you leverage that... even the tiniest prod can sufficiently topple any resistance.","TWN":"好好利用這一點，一些小小的刺激就能讓他們的反抗心徹底崩塌。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그 여자...... 재조립되면서 정말 아름답게 지저귀더구나.","JPN":"あの女……組み直されながら実に美しく叫んでいた。","ENG":"As for the woman... How beautifully she chirped as she was reassembled.","TWN":"那個女人……重新組裝的時候，叫聲真是美麗。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그들에게 죄가 있다면 타기리온의 눈에 띄었다는 것뿐이다.","JPN":"彼女らに罪があるとすれば、タギリオンの目に留まったということだけだ。","ENG":"Their only crime is that they unwittingly drew Thagirion's attention.","TWN":"如果說他們有罪的話，就是不應該出現在塔基里翁眼前。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는 저들이 당한 모욕을...... 장난인 양 떠드는구나.","JPN":"お前は彼女らが受けた侮辱を……イタズラのようなものとほざいておる。","ENG":"And yet you jest... as if their suffering was but child's play.","TWN":"你侮辱欺騙她們……卻洋洋自得。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"말하지 않았느냐, 방랑자. 그분의 계획에 만약이란 존재할 수 없도다.","JPN":"言ったはずだ、放浪者よ。あのお方の計画に万が一は存在しないと。","ENG":"Have I not told you, Wayfarer? The king's plans are inevitable.","TWN":"我不是說了嗎，流浪者。王的計畫沒有萬一。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"한낱 미물들의 목숨으로 왕께서 만족하신다면, 분수에 넘치게 값진 결말일 터.","JPN":"一介の微物の命で王が満足されるなら、身に余るほどの貴重な結末に間違いない。","ENG":"If the queen finds their petty lives pleasing, there is no greater glory for these mere mortals.","TWN":"如果區區一個微不足道的廢物性命能讓我的王滿意，那就是非常有價值的。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그것이...... 왕을 자처하는 자로서 올바른 행동인가?","JPN":"それが……王を名乗る者として正しい行動なのか？","ENG":"Tell me... Is that behavior truly fitting of a self-proclaimed queen?","TWN":"這……是作為以王自居的人的正確行為嗎？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"희생양들의 영혼을 자신의 욕망으로 일그러뜨리고, 꼭두각시로 만드는 것이?","JPN":"犠牲者の魂を自らの欲望で壊して、操り人形にすることが？","ENG":"To soil the souls of the innocent and turn them into puppets?","TWN":"把犧牲品的靈魂扭曲成自己的欲望，變成傀儡？"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"......불경한 것. 네가 아직도 훈계 따위를 늘어놓을 위치라고 생각하느냐.","JPN":"……不敬者。貴様がまだ訓戒を垂れる立場だと思うのか。","ENG":"Blasphemous fool. Do you really think you are still in a position to lecture thusly?","TWN":"……倡狂的東西。你以為你有資格訓誡我嗎。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"왕께서 걸음 하실 때, 너는 이번에야말로 덧없이 사라지게 되리라.","JPN":"王が降臨される際、今度こそ貴様は儚く消えるのであろう。","ENG":"When the queen proceeds, you shall finally perish into oblivion, once and for all.","TWN":"當王能夠行動時，也就是你灰飛煙滅的時刻。"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_04","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};